import React, { useState, useEffect } from 'react';

const App = () => {
  const [typedText, setTypedText] = useState('');
  const [showContent, setShowContent] = useState(false);
  const [currentLine, setCurrentLine] = useState(0);

  const commands = [
    'zenu@dev:~$ sudo ./init-portfolio.sh',
    '[sudo] password for zenu: ********',
    'zenu@dev:~$ loading developer profile...',
    'zenu@dev:~$ initializing tech stack...',
    'zenu@dev:~$ mounting experience drive...',
    'zenu@dev:~$ starting services...',
    'zenu@dev:~$ ✓ All systems operational'
  ];

  const techStack = [
    { name: 'JavaScript', level: 95 },
    { name: 'Swift', level: 90 },
    { name: 'Kotlin', level: 88 },
    { name: 'Node.js', level: 92 },
    { name: 'React', level: 94 },
    { name: 'Jetpack Compose', level: 85 },
    { name: 'SwiftUI', level: 87 },
    { name: 'MongoDB', level: 82 },
    { name: 'Firebase', level: 84 }
  ];

  const experience = [
    {
      role: 'Senior Full Stack Developer',
      company: 'Tech Company',
      period: '2022 - Present',
      description: 'Leading development of scalable web and mobile applications'
    },
    {
      role: 'iOS Developer',
      company: 'App Studio',
      period: '2020 - 2022',
      description: 'Developed and maintained multiple iOS applications'
    }
  ];

  const projects = [
    {
      name: 'E-Commerce Platform',
      tech: 'React, Node.js, MongoDB',
      status: 'Production'
    },
    {
      name: 'iOS Fitness App',
      tech: 'Swift, SwiftUI',
      status: 'App Store'
    },
    {
      name: 'Android Banking App',
      tech: 'Kotlin, Jetpack Compose',
      status: 'Play Store'
    }
  ];

  useEffect(() => {
    let timeout;
    let charIndex = 0;
    let lineIndex = 0;

    const typeNextChar = () => {
      if (lineIndex < commands.length) {
        const currentCommand = commands[lineIndex];

        if (charIndex < currentCommand.length) {
          setTypedText(prev => {
            const lines = prev.split('\n');
            if (lines.length <= lineIndex) {
              lines.push('');
            }
            lines[lineIndex] = currentCommand.substring(0, charIndex + 1);
            return lines.join('\n');
          });
          charIndex++;
          timeout = setTimeout(typeNextChar, 50 + Math.random() * 50);
        } else {
          charIndex = 0;
          lineIndex++;
          timeout = setTimeout(typeNextChar, 400);
        }
      } else {
        setShowContent(true);
      }
    };

    typeNextChar();

    return () => clearTimeout(timeout);
  }, []);

  return (
    <div className="terminal-container">
      <div className="terminal-window">
        <div className="terminal-header">
          <div className="terminal-buttons">
            <div className="terminal-button close"></div>
            <div className="terminal-button minimize"></div>
            <div className="terminal-button maximize"></div>
          </div>
          <div className="terminal-title">zenu@dev:~</div>
        </div>
        <div className="terminal-body">
          <div className="terminal-output">
            <pre className="typing-text">{typedText}</pre>
            <span className="cursor">█</span>
          </div>

          {showContent && (
            <div className="terminal-content fade-in">
              <div className="welcome-section">
                <h1 className="greeting">
                  <span className="prompt">zenu@dev:~$</span> whoami
                </h1>
                <div className="developer-info">
                  <p className="developer-name">
                    <span className="accent">→</span> Hamzah Mohandeszade (Zenu)
                  </p>
                  <p className="developer-title">Full Stack Developer | iOS & Android Specialist</p>
                  <p className="developer-location">
                    <span className="icon">📍</span> Berlin, Germany
                  </p>
                  <p className="developer-status">
                    <span className="status-dot"></span>
                    Available for freelance projects
                  </p>
                </div>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> cat tech-stack.txt
                </h2>
                <div className="tech-grid">
                  {techStack.map((tech, index) => (
                    <div key={index} className="tech-item">
                      <div className="tech-header">
                        <span className="tech-bullet">▸</span>
                        <span className="tech-name">{tech.name}</span>
                      </div>
                      <div className="tech-bar">
                        <div 
                          className="tech-progress" 
                          style={{ width: `${tech.level}%` }}
                        ></div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> cat experience.log
                </h2>
                <div className="experience-list">
                  {experience.map((exp, index) => (
                    <div key={index} className="experience-item">
                      <div className="exp-header">
                        <span className="exp-role">{exp.role}</span>
                        <span className="exp-period">{exp.period}</span>
                      </div>
                      <div className="exp-company">@ {exp.company}</div>
                      <div className="exp-description">{exp.description}</div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> ls -la projects/
                </h2>
                <div className="projects-list">
                  {projects.map((project, index) => (
                    <div key={index} className="project-item">
                      <div className="project-header">
                        <span className="project-name">{project.name}</span>
                        <span className="project-status">{project.status}</span>
                      </div>
                      <div className="project-tech">{project.tech}</div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="section">
                <h2 className="section-title">
                  <span className="prompt">zenu@dev:~$</span> ls -la contact/
                </h2>
                <div className="contact-links">
                  <a href="https://github.com/zenu" target="_blank" rel="noopener noreferrer" className="contact-link">
                    <span className="path">./github</span>
                  </a>
                  <a href="https://linkedin.com/in/hamzah-mohandeszade" target="_blank" rel="noopener noreferrer" className="contact-link">
